// Parse the LLM response and normalise to a known intent.
// Valid intents: temp | cpu | memory | disk | full
const raw = ($input.first().json?.response || '').trim().toLowerCase().replace(/[^a-z]/g, '');
const userMessage = $('Telegram Trigger').first().json.message?.text || '';

const valid = ['temp', 'cpu', 'memory', 'disk', 'full'];
const intent = valid.includes(raw) ? raw : 'full';

return [{ json: { intent, userMessage } }];

const t = $input.first().json?.data || {};

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return '?';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

const cpu  = t['k10temp-pci-00c3']?.Tctl?.temp1_input  ?? 'N/A';
const gpu  = t['amdgpu-pci-0500']?.edge?.temp1_input   ?? 'N/A';
const nvme = t['nvme-pci-0400']?.Composite?.temp1_input ?? 'N/A';

const cpuSt  = label(cpu,  85, 95);
const nvmeSt = label(nvme, 70, 80);

const header = `*Temperatures*\nCPU: ${cpu}°C [${cpuSt}] | GPU: ${gpu}°C | NVMe: ${nvme}°C [${nvmeSt}]`;

const prompt = `You are a concise homelab assistant. Write ONE short sentence (max 15 words) summarising the thermal status for a Proxmox server given these sensor readings:
- CPU (k10temp): ${cpu}°C, status ${cpuSt} (warn≥85, crit≥95)
- GPU (amdgpu): ${gpu}°C
- NVMe: ${nvme}°C, status ${nvmeSt} (warn≥70, crit≥80)
Be specific and natural. No markdown, no bullet points.`;

return [{ json: { header, prompt } }];

const s = $input.first().json?.data || {};
const intent = $('Parse LLM Intent').first().json.intent;

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return '?';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

const cpuPct = ((s.cpu || 0) * 100).toFixed(1);
const cpuSt  = label(cpuPct, 80, 95);
const load   = (s.loadavg || []).join(', ');

const ramPct = s.memory?.total
  ? ((s.memory.used / s.memory.total) * 100).toFixed(1) : 'N/A';
const ramSt  = label(ramPct, 85, 95);
const ramUsedGB = s.memory?.used  ? (s.memory.used  / 1073741824).toFixed(1) : '?';
const ramTotGB  = s.memory?.total ? (s.memory.total / 1073741824).toFixed(1) : '?';
const swapPct   = s.swap?.total
  ? ((s.swap.used / s.swap.total) * 100).toFixed(1) : '0.0';

let header, prompt;
if (intent === 'cpu') {
  header = `*CPU*\nUsage: ${cpuPct}% [${cpuSt}] | Load avg: ${load}`;
  prompt = `You are a concise homelab assistant. Write ONE short sentence (max 15 words) summarising the CPU status for a Proxmox server:
- CPU usage: ${cpuPct}%, status ${cpuSt} (warn≥80, crit≥95)
- Load averages: ${load}
Be specific and natural. No markdown, no bullet points.`;
} else {
  header = `*Memory*\nRAM: ${ramUsedGB} / ${ramTotGB} GB (${ramPct}%) [${ramSt}] | Swap: ${swapPct}%`;
  prompt = `You are a concise homelab assistant. Write ONE short sentence (max 15 words) summarising the memory status for a Proxmox server:
- RAM usage: ${ramUsedGB} GB of ${ramTotGB} GB (${ramPct}%), status ${ramSt} (warn≥85, crit≥95)
- Swap: ${swapPct}%
Be specific and natural. No markdown, no bullet points.`;
}

return [{ json: { header, prompt } }];

const disk = $input.first().json?.data || [];

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return '?';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

const lines = disk.map(d => {
  const pct = (d.used_fraction * 100).toFixed(1);
  const freeGB = (d.avail / 1073741824).toFixed(1);
  return `- ${d.storage} (${d.type}): ${pct}% used, ${freeGB} GB free [${label(pct, 80, 90)}]`;
}).join('\n');

const worst = disk.reduce((acc, d) => Math.max(acc, d.used_fraction * 100), 0);
const worstSt = label(worst, 80, 90);

const header = `*Storage*\n${lines}`;

const diskSummary = disk.map(d => {
  const pct = (d.used_fraction * 100).toFixed(1);
  const freeGB = (d.avail / 1073741824).toFixed(1);
  return `${d.storage}: ${pct}% used, ${freeGB} GB free`;
}).join('; ');

const prompt = `You are a concise homelab assistant. Write ONE short sentence (max 15 words) summarising the storage status for a Proxmox server:
- Pools: ${diskSummary}
- Worst pool: ${worst.toFixed(1)}%, status ${worstSt} (warn≥80, crit≥90)
Be specific and natural. No markdown, no bullet points.`;

return [{ json: { header, prompt } }];

const header = $('Format Temp').first().json.header;
const sentence = ($input.first().json?.response || '').trim();
const text = `${header}\n_${sentence}_`;
return [{ json: { text } }];

const header = $('Format CPU or RAM').first().json.header;
const sentence = ($input.first().json?.response || '').trim();
const text = `${header}\n_${sentence}_`;
return [{ json: { text } }];

const header = $('Format Disk').first().json.header;
const sentence = ($input.first().json?.response || '').trim();
const text = `${header}\n_${sentence}_`;
return [{ json: { text } }];

const t = $('Fetch Temp (Full)').first().json?.data || {};
const s = $('Fetch Status (Full)').first().json?.data || {};
const disk = $('Fetch Disk (Full)').first().json?.data || [];

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return 'UNKNOWN';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

// Temperatures
const cpuTemp  = t['k10temp-pci-00c3']?.Tctl?.temp1_input  ?? 'N/A';
const gpuTemp  = t['amdgpu-pci-0500']?.edge?.temp1_input   ?? 'N/A';
const nvmeTemp = t['nvme-pci-0400']?.Composite?.temp1_input ?? 'N/A';
const cpuTempSt  = label(cpuTemp, 85, 95);
const nvmeTempSt = label(nvmeTemp, 70, 80);

// CPU & RAM
const cpuPct    = ((s.cpu || 0) * 100).toFixed(1);
const load      = (s.loadavg || []).join(', ');
const cpuSt     = label(cpuPct, 80, 95);
const ramPct    = s.memory?.total ? ((s.memory.used / s.memory.total) * 100).toFixed(1) : 'N/A';
const ramSt     = label(ramPct, 85, 95);
const ramUsedGB = s.memory?.used  ? (s.memory.used  / 1073741824).toFixed(1) : '?';
const ramTotGB  = s.memory?.total ? (s.memory.total / 1073741824).toFixed(1) : '?';
const swapPct   = s.swap?.total ? ((s.swap.used / s.swap.total) * 100).toFixed(1) : '0.0';

// Disk
const diskLines = disk.map(d => {
  const pct = (d.used_fraction * 100).toFixed(1);
  const freeGB = (d.avail / 1073741824).toFixed(1);
  const st = label(pct, 80, 90);
  return { name: d.storage, pct, freeGB, st };
});
const diskSummary = diskLines.map(d => `${d.name}: ${d.pct}% used, ${d.freeGB} GB free [${d.st}]`).join('; ');

const header =
  `*Full Homelab Status*\n`
  + `*Temp:* CPU ${cpuTemp}°C [${cpuTempSt}] | GPU ${gpuTemp}°C | NVMe ${nvmeTemp}°C [${nvmeTempSt}]\n`
  + `*CPU:* ${cpuPct}% [${cpuSt}] | Load: ${load}\n`
  + `*RAM:* ${ramUsedGB}/${ramTotGB} GB (${ramPct}%) [${ramSt}] | Swap: ${swapPct}%\n`
  + `*Disk:* ${diskSummary}`;

// Build a plain-English status list for the LLM — no threshold re-evaluation needed
const statusLines = [
  `CPU temperature: ${cpuTemp}°C — status is ${cpuTempSt}`,
  `GPU temperature: ${gpuTemp}°C`,
  `NVMe temperature: ${nvmeTemp}°C — status is ${nvmeTempSt}`,
  `CPU usage: ${cpuPct}% — status is ${cpuSt}`,
  `Load averages: ${load}`,
  `RAM: ${ramUsedGB}/${ramTotGB} GB (${ramPct}%) — status is ${ramSt}`,
  `Swap: ${swapPct}%`,
  ...diskLines.map(d => `Storage ${d.name}: ${d.pct}% used, ${d.freeGB} GB free — status is ${d.st}`),
].join('\n');

const warnOrCrit = [cpuTempSt, nvmeTempSt, cpuSt, ramSt, ...diskLines.map(d => d.st)]
  .some(st => st === 'WARN' || st === 'CRIT');

const prompt =
  `You are a concise homelab assistant. Write 2-3 short sentences summarising the overall health of a Proxmox server.\n`
  + `The statuses below have already been evaluated — do NOT re-evaluate or contradict them.\n`
  + `Use the status labels (OK / WARN / CRIT) exactly as given. Only mention concerns for items labelled WARN or CRIT.\n`
  + (warnOrCrit ? '' : `All metrics are OK — keep the summary positive and brief.\n`)
  + `No markdown, no bullet points.\n\n`
  + statusLines;

return [{ json: { header, prompt } }];

const header = $('Aggregate Full Metrics').first().json.header;
const sentence = ($input.first().json?.response || '').trim();
const text = `${header}\n\n_${sentence}_`;
return [{ json: { text } }];
